import pytest


def memoize(fn):
    cache = {}

    def wrapper(*args):
        if args not in cache:
            cache[args] = fn(*args)
        return cache[args]

    return wrapper


def test_memoize_caches_result_for_same_arguments():
    calls = {"count": 0}

    def add(a, b):
        calls["count"] += 1
        return a + b

    memoized_add = memoize(add)

    assert memoized_add(1, 2) == 3
    assert memoized_add(1, 2) == 3
    assert calls["count"] == 1


def test_memoize_calls_function_again_for_different_arguments():
    calls = {"count": 0}

    def add(a, b):
        calls["count"] += 1
        return a + b

    memoized_add = memoize(add)

    assert memoized_add(1, 2) == 3
    assert memoized_add(2, 3) == 5
    assert memoized_add(1, 2) == 3
    assert calls["count"] == 2


def test_memoize_works_with_no_arguments():
    calls = {"count": 0}

    def get_value():
        calls["count"] += 1
        return "cached"

    memoized_get_value = memoize(get_value)

    assert memoized_get_value() == "cached"
    assert memoized_get_value() == "cached"
    assert calls["count"] == 1


def test_memoize_distinguishes_argument_order():
    calls = {"count": 0}

    def pair(a, b):
        calls["count"] += 1
        return (a, b)

    memoized_pair = memoize(pair)

    assert memoized_pair(1, 2) == (1, 2)
    assert memoized_pair(2, 1) == (2, 1)
    assert calls["count"] == 2


def test_memoize_caches_none_result():
    calls = {"count": 0}

    def returns_none(x):
        calls["count"] += 1
        return None

    memoized_fn = memoize(returns_none)

    assert memoized_fn(1) is None
    assert memoized_fn(1) is None
    assert calls["count"] == 1


def test_memoize_propagates_exception_and_does_not_cache_failed_call():
    calls = {"count": 0}

    def always_fails(x):
        calls["count"] += 1
        raise ValueError("boom")

    memoized_fn = memoize(always_fails)

    with pytest.raises(ValueError, match="boom"):
        memoized_fn(1)

    with pytest.raises(ValueError, match="boom"):
        memoized_fn(1)

    assert calls["count"] == 2


def test_memoize_raises_type_error_for_unhashable_arguments():
    def identity(x):
        return x

    memoized_fn = memoize(identity)

    with pytest.raises(TypeError):
        memoized_fn([1, 2, 3])


